package com.schoolbus.dto.response;
import com.schoolbus.entity.Student; import java.math.*; import java.time.*;
public record StudentResponse(Long id,String studentCode,String firstName,String lastName,String grade,String section,String gender,Long parentId,String parentName,String pickupAddress,String dropAddress,BigDecimal pickupLatitude,BigDecimal pickupLongitude,BigDecimal dropLatitude,BigDecimal dropLongitude,String rfidTag,Boolean active,LocalDate dateOfBirth) { public static StudentResponse from(Student s){var p=s.getParent();return new StudentResponse(s.getId(),s.getStudentCode(),s.getFirstName(),s.getLastName(),s.getGrade(),s.getSection(),s.getGender(),p==null?null:p.getId(),p==null?null:p.getUser().getFullName(),s.getPickupAddress(),s.getDropAddress(),s.getPickupLatitude(),s.getPickupLongitude(),s.getDropLatitude(),s.getDropLongitude(),s.getRfidTag(),s.getActive(),s.getDateOfBirth());} }
